// pages/student/StudentProfile.jsx
import React, { useState } from 'react';
import './StudentProfile.css';

const ALL_SKILLS = ['React', 'JavaScript', 'TypeScript', 'CSS', 'HTML', 'Node.js', 'Python',
  'Java', 'SQL', 'MongoDB', 'Git', 'Docker', 'AWS', 'Figma', 'Machine Learning',
  'REST APIs', 'GraphQL', 'Redux', 'Spring Boot', 'TensorFlow'];

const DEGREES = ['B.Tech', 'B.E.', 'B.Sc', 'BCA', 'MBA', 'M.Tech', 'M.Sc', 'MCA', 'BBA', 'B.Com'];
const BRANCHES = ['Computer Science', 'Information Technology', 'Electronics', 'Mechanical', 'Civil',
  'Electrical', 'Data Science', 'AI/ML', 'Chemical', 'Biotechnology'];
const YEARS = ['1st Year', '2nd Year', '3rd Year', '4th Year', 'Graduate', 'Post Graduate'];

const INITIAL = {
  firstName: 'User', lastName: 'Name',
  email: 'user.nam@xyzcollege.edu',
  phone: '+91 98765 43210',
  college: 'XYZ Engineering College',
  degree: 'B.Tech', branch: 'Computer Science', year: '3rd Year',
  cgpa: '8.4',
  bio: 'Passionate full-stack developer with a focus on building clean, scalable web applications. Looking for internship opportunities in product-focused startups.',
  skills: ['React', 'JavaScript', 'CSS', 'Node.js', 'Git'],
  linkedin: 'https://linkedin.com/in/username',
  github: 'https://github.com/username',
  portfolio: '',
  resumeFileName: 'User_Name_Resume.pdf',
  availableFrom: '2025-06-01',
  preferredRoles: ['Frontend', 'Full Stack'],
  preferredLocations: ['Remote', 'Bangalore'],
  lookingFor: 'internship',
};

const ROLES = ['Frontend', 'Backend', 'Full Stack', 'Data Science', 'Design', 'DevOps', 'Marketing', 'Product', 'Management'];
const LOCATIONS_OPT = ['Remote', 'Bangalore', 'Mumbai', 'Hyderabad', 'Delhi', 'Pune', 'Chennai'];

function Section({ title, icon, children, action }) {
  return (
    <div className="sprofile__section">
      <div className="sprofile__section-header">
        <div className="sprofile__section-title-row">
          <span className="sprofile__section-icon">{icon}</span>
          <h3 className="sprofile__section-title">{title}</h3>
        </div>
        {action}
      </div>
      <div className="sprofile__section-body">
        {children}
      </div>
    </div>
  );
}

export default function StudentProfile() {
  const [data, setData] = useState(INITIAL);
  const [editing, setEditing] = useState(null); // section key
  const [draft, setDraft] = useState({});
  const [saved, setSaved] = useState(false);

  const startEdit = (section) => {
    setDraft({ ...data });
    setEditing(section);
    setSaved(false);
  };

  const cancelEdit = () => { setEditing(null); setDraft({}); };

  const saveEdit = (section) => {
    setData({ ...data, ...draft });
    setEditing(null);
    setDraft({});
    setSaved(true);
    setTimeout(() => setSaved(false), 2500);
  };

  const set = (key, value) => setDraft(d => ({ ...d, [key]: value }));

  const toggleArrayItem = (key, item) => {
    const arr = draft[key] || [];
    set(key, arr.includes(item) ? arr.filter(x => x !== item) : [...arr, item]);
  };

  const initials = `${data.firstName[0]}${data.lastName[0]}`.toUpperCase();

  // Profile completion calc
  const fields = [data.firstName, data.lastName, data.email, data.phone, data.college,
    data.degree, data.bio, data.skills.length > 0, data.linkedin, data.github, data.resumeFileName];
  const completion = Math.round((fields.filter(Boolean).length / fields.length) * 100);

  return (
    <div className="sprofile page-enter">

      {/* Save toast */}
      {saved && (
        <div className="sprofile__toast">✓ Profile updated successfully!</div>
      )}

      {/* ── HEADER CARD ── */}
      <div className="sprofile__hero">
        <div className="sprofile__hero-bg" />
        <div className="sprofile__hero-content">
          <div className="sprofile__avatar-wrap">
            <div className="sprofile__avatar">{initials}</div>
            <button className="sprofile__avatar-edit" title="Change photo">📷</button>
          </div>
          <div className="sprofile__hero-info">
            <h2 className="sprofile__name">{data.firstName} {data.lastName}</h2>
            <p className="sprofile__tagline">{data.degree} {data.branch} · {data.college}</p>
            <p className="sprofile__tagline">{data.year} · CGPA: {data.cgpa}</p>
            <div className="sprofile__hero-links">
              {data.linkedin  && <a href={data.linkedin}  className="sprofile__link sprofile__link--blue"  target="_blank" rel="noreferrer">in LinkedIn</a>}
              {data.github    && <a href={data.github}    className="sprofile__link sprofile__link--dark"  target="_blank" rel="noreferrer">⌥ GitHub</a>}
              {data.portfolio && <a href={data.portfolio} className="sprofile__link sprofile__link--lavender" target="_blank" rel="noreferrer">🌐 Portfolio</a>}
            </div>
          </div>
          {/* Completion ring */}
          <div className="sprofile__completion">
            <svg viewBox="0 0 80 80" className="sprofile__ring-svg">
              <circle cx="40" cy="40" r="34" fill="none" stroke="var(--border-subtle)" strokeWidth="6"/>
              <circle cx="40" cy="40" r="34" fill="none" stroke="var(--lavender)" strokeWidth="6"
                strokeDasharray="213.6"
                strokeDashoffset={213.6 - (213.6 * completion / 100)}
                strokeLinecap="round" transform="rotate(-90 40 40)" />
            </svg>
            <div className="sprofile__ring-text">
              <span className="sprofile__ring-pct">{completion}%</span>
              <span className="sprofile__ring-label">Complete</span>
            </div>
          </div>
        </div>
      </div>

      <div className="sprofile__body">
        <div className="sprofile__main">

          {/* ── BASIC INFO ── */}
          <Section
            title="Basic Information" icon="👤"
            action={editing !== 'basic'
              ? <button className="sprofile__edit-btn" onClick={() => startEdit('basic')}>✏️ Edit</button>
              : <div className="sprofile__edit-actions">
                  <button className="btn btn-ghost btn-sm" onClick={cancelEdit}>Cancel</button>
                  <button className="btn btn-primary btn-sm" onClick={() => saveEdit('basic')}>Save</button>
                </div>
            }>
            {editing === 'basic' ? (
              <div className="sprofile__form-grid">
                {[['firstName','First Name','text'], ['lastName','Last Name','text'],
                  ['email','Email','email'], ['phone','Phone','tel']].map(([k, label, type]) => (
                  <div key={k} className="form-group">
                    <label className="form-label">{label}</label>
                    <input className="form-input" type={type} value={draft[k] || ''} onChange={e => set(k, e.target.value)} />
                  </div>
                ))}
                <div className="form-group sprofile__form-full">
                  <label className="form-label">Bio / About Me</label>
                  <textarea
                    className="form-input sprofile__textarea"
                    value={draft.bio || ''}
                    onChange={e => set('bio', e.target.value)}
                    placeholder="Tell employers about yourself..."
                    rows={4}
                  />
                </div>
              </div>
            ) : (
              <div className="sprofile__info-grid">
                {[['📧', 'Email', data.email], ['📱', 'Phone', data.phone]].map(([icon, label, val]) => (
                  <div key={label} className="sprofile__info-item">
                    <span className="sprofile__info-icon">{icon}</span>
                    <div>
                      <span className="sprofile__info-label">{label}</span>
                      <span className="sprofile__info-val">{val || <em style={{color:'var(--text-muted)'}}>Not added</em>}</span>
                    </div>
                  </div>
                ))}
                {data.bio && <p className="sprofile__bio">{data.bio}</p>}
              </div>
            )}
          </Section>

          {/* ── EDUCATION ── */}
          <Section
            title="Education" icon="🎓"
            action={editing !== 'edu'
              ? <button className="sprofile__edit-btn" onClick={() => startEdit('edu')}>✏️ Edit</button>
              : <div className="sprofile__edit-actions">
                  <button className="btn btn-ghost btn-sm" onClick={cancelEdit}>Cancel</button>
                  <button className="btn btn-primary btn-sm" onClick={() => saveEdit('edu')}>Save</button>
                </div>
            }>
            {editing === 'edu' ? (
              <div className="sprofile__form-grid">
                <div className="form-group sprofile__form-full">
                  <label className="form-label">College / University</label>
                  <input className="form-input" type="text" value={draft.college || ''} onChange={e => set('college', e.target.value)} placeholder="e.g. IIT Bombay" />
                </div>
                <div className="form-group">
                  <label className="form-label">Degree</label>
                  <select className="form-select" value={draft.degree || ''} onChange={e => set('degree', e.target.value)}>
                    {DEGREES.map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Branch / Specialization</label>
                  <select className="form-select" value={draft.branch || ''} onChange={e => set('branch', e.target.value)}>
                    {BRANCHES.map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Current Year</label>
                  <select className="form-select" value={draft.year || ''} onChange={e => set('year', e.target.value)}>
                    {YEARS.map(y => <option key={y} value={y}>{y}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">CGPA / Percentage</label>
                  <input className="form-input" type="text" value={draft.cgpa || ''} onChange={e => set('cgpa', e.target.value)} placeholder="e.g. 8.5" />
                </div>
              </div>
            ) : (
              <div className="sprofile__edu-card">
                <div className="sprofile__edu-icon">🏛️</div>
                <div>
                  <h4 className="sprofile__edu-college">{data.college}</h4>
                  <p className="sprofile__edu-degree">{data.degree} in {data.branch}</p>
                  <div className="sprofile__edu-meta">
                    <span className="tag tag-lavender">{data.year}</span>
                    {data.cgpa && <span className="tag tag-mint">CGPA: {data.cgpa}</span>}
                  </div>
                </div>
              </div>
            )}
          </Section>

          {/* ── SKILLS ── */}
          <Section
            title="Skills" icon="⚡"
            action={editing !== 'skills'
              ? <button className="sprofile__edit-btn" onClick={() => startEdit('skills')}>✏️ Edit</button>
              : <div className="sprofile__edit-actions">
                  <button className="btn btn-ghost btn-sm" onClick={cancelEdit}>Cancel</button>
                  <button className="btn btn-primary btn-sm" onClick={() => saveEdit('skills')}>Save</button>
                </div>
            }>
            {editing === 'skills' ? (
              <div>
                <p className="sprofile__edit-hint">Select skills you're proficient in:</p>
                <div className="sprofile__skill-picker">
                  {ALL_SKILLS.map(skill => {
                    const active = (draft.skills || []).includes(skill);
                    return (
                      <button
                        key={skill}
                        className={`sprofile__skill-pill ${active ? 'sprofile__skill-pill--active' : ''}`}
                        onClick={() => toggleArrayItem('skills', skill)}>
                        {active ? '✓ ' : ''}{skill}
                      </button>
                    );
                  })}
                </div>
              </div>
            ) : (
              <div className="sprofile__skills-display">
                {data.skills.length > 0
                  ? data.skills.map(s => <span key={s} className="tag tag-lavender sprofile__skill-tag">{s}</span>)
                  : <p className="sprofile__empty-hint">No skills added yet — click Edit to add some.</p>
                }
              </div>
            )}
          </Section>

          {/* ── PREFERENCES ── */}
          <Section
            title="Job Preferences" icon="🎯"
            action={editing !== 'pref'
              ? <button className="sprofile__edit-btn" onClick={() => startEdit('pref')}>✏️ Edit</button>
              : <div className="sprofile__edit-actions">
                  <button className="btn btn-ghost btn-sm" onClick={cancelEdit}>Cancel</button>
                  <button className="btn btn-primary btn-sm" onClick={() => saveEdit('pref')}>Save</button>
                </div>
            }>
            {editing === 'pref' ? (
              <div className="sprofile__pref-editor">
                <div className="form-group">
                  <label className="form-label">Looking For</label>
                  <div className="sprofile__radio-row">
                    {['internship', 'full-time', 'both'].map(opt => (
                      <button
                        key={opt}
                        className={`sprofile__radio-btn ${draft.lookingFor === opt ? 'sprofile__radio-btn--active' : ''}`}
                        onClick={() => set('lookingFor', opt)}>
                        {opt === 'internship' ? '🎓 Internship' : opt === 'full-time' ? '💼 Full-Time' : '🌐 Both'}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Available From</label>
                  <input className="form-input" type="date" value={draft.availableFrom || ''} onChange={e => set('availableFrom', e.target.value)} />
                </div>
                <div className="form-group">
                  <label className="form-label">Preferred Roles</label>
                  <div className="sprofile__pill-picker">
                    {ROLES.map(r => {
                      const active = (draft.preferredRoles || []).includes(r);
                      return (
                        <button key={r} className={`filter-chip ${active ? 'filter-chip--active' : ''}`}
                          onClick={() => toggleArrayItem('preferredRoles', r)}>{r}</button>
                      );
                    })}
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Preferred Locations</label>
                  <div className="sprofile__pill-picker">
                    {LOCATIONS_OPT.map(l => {
                      const active = (draft.preferredLocations || []).includes(l);
                      return (
                        <button key={l} className={`filter-chip ${active ? 'filter-chip--active' : ''}`}
                          onClick={() => toggleArrayItem('preferredLocations', l)}>{l}</button>
                      );
                    })}
                  </div>
                </div>
              </div>
            ) : (
              <div className="sprofile__pref-display">
                {[
                  ['🎯', 'Looking for', data.lookingFor === 'both' ? 'Internship & Full-Time' : data.lookingFor],
                  ['📅', 'Available from', data.availableFrom],
                  ['💼', 'Preferred roles', data.preferredRoles.join(', ')],
                  ['📍', 'Preferred locations', data.preferredLocations.join(', ')],
                ].map(([icon, label, val]) => (
                  <div key={label} className="sprofile__pref-item">
                    <span>{icon}</span>
                    <div>
                      <span className="sprofile__info-label">{label}</span>
                      <span className="sprofile__info-val">{val || <em style={{color:'var(--text-muted)'}}>Not set</em>}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </Section>

          {/* ── LINKS ── */}
          <Section
            title="Links & Resume" icon="🔗"
            action={editing !== 'links'
              ? <button className="sprofile__edit-btn" onClick={() => startEdit('links')}>✏️ Edit</button>
              : <div className="sprofile__edit-actions">
                  <button className="btn btn-ghost btn-sm" onClick={cancelEdit}>Cancel</button>
                  <button className="btn btn-primary btn-sm" onClick={() => saveEdit('links')}>Save</button>
                </div>
            }>
            {editing === 'links' ? (
              <div className="sprofile__form-grid">
                {[
                  ['linkedin',  '🔷 LinkedIn URL',  'https://linkedin.com/in/...'],
                  ['github',    '⌥ GitHub URL',    'https://github.com/...'],
                  ['portfolio', '🌐 Portfolio URL', 'https://yoursite.com'],
                ].map(([k, label, placeholder]) => (
                  <div key={k} className="form-group sprofile__form-full">
                    <label className="form-label">{label}</label>
                    <input className="form-input" type="url" value={draft[k] || ''} onChange={e => set(k, e.target.value)} placeholder={placeholder} />
                  </div>
                ))}
                <div className="form-group sprofile__form-full">
                  <label className="form-label">Resume</label>
                  <div className="sprofile__resume-upload">
                    <span>📄 {data.resumeFileName || 'No resume uploaded'}</span>
                    <button className="btn btn-ghost btn-sm">Upload New PDF</button>
                  </div>
                </div>
              </div>
            ) : (
              <div className="sprofile__links-display">
                {[
                  [data.linkedin,  '🔷', 'LinkedIn',  data.linkedin],
                  [data.github,    '⌥',  'GitHub',    data.github],
                  [data.portfolio, '🌐', 'Portfolio', data.portfolio],
                ].filter(([val]) => val).map(([, icon, label, url]) => (
                  <a key={label} href={url} target="_blank" rel="noreferrer" className="sprofile__link-item">
                    <span>{icon}</span>
                    <span>{label}</span>
                    <span className="sprofile__link-url">{url}</span>
                  </a>
                ))}
                {data.resumeFileName && (
                  <div className="sprofile__resume-pill">
                    <span>📄</span>
                    <span>{data.resumeFileName}</span>
                    <button className="btn btn-ghost btn-sm" style={{ marginLeft: 'auto' }}>Download</button>
                  </div>
                )}
              </div>
            )}
          </Section>

        </div>
      </div>
    </div>
  );
}
